public class RuntimePolymorphism {

    static abstract class Animal {
        String name;
        Animal(String name) { this.name = name; }
        abstract void speak(); // each subclass defines this
        void breathe() { System.out.println(name + " breathes"); } // shared
    }

    static class Dog extends Animal {
        Dog(String name) { super(name); }
        @Override void speak() { System.out.println(name + ": Woof!"); }
    }

    static class Cat extends Animal {
        Cat(String name) { super(name); }
        @Override void speak() { System.out.println(name + ": Meow!"); }
    }

    static class Parrot extends Animal {
        String phrase;
        Parrot(String name, String phrase) { super(name); this.phrase = phrase; }
        @Override void speak() { System.out.println(name + ": " + phrase); }
    }

    // This method works for ALL Animal subtypes — present and future!
    static void makeItSpeak(Animal a) {
        a.speak(); // JVM dispatches to actual type's speak() at runtime
    }

    public static void main(String[] args) {
        Animal[] zoo = {
            new Dog("Rex"),
            new Cat("Whiskers"),
            new Parrot("Polly", "Polly wants a cracker")
        };

        // Polymorphic iteration — no instanceof, no casting
        for (Animal a : zoo) {
            makeItSpeak(a); // correct speak() called for each actual type
            a.breathe();    // inherited from Animal — same for all
        }
    }
}

public class MethodOverloading {

    static class Printer {

        // Same logical operation 'print', different parameter types
        void print(int value) {
            System.out.println("int: " + value);
        }

        void print(double value) {
            System.out.println("double: " + value);
        }

        void print(String value) {
            System.out.println("String: \"" + value + "\"");
        }

        void print(int a, int b) {       // different arity
            System.out.println("two ints: " + a + ", " + b);
        }

        void print(String label, int value) { // different order matters
            System.out.println(label + " = " + value);
        }

        // INVALID — return type alone does not distinguish overloads:
        // int  getValue() { return 1; }   ← compile error:
        // void getValue() { }              ← same name + params, different return
    }

    public static void main(String[] args) {
        Printer p = new Printer();

        p.print(42);            // resolves to print(int)
        p.print(3.14);          // resolves to print(double)
        p.print("hello");       // resolves to print(String)
        p.print(1, 2);          // resolves to print(int, int)
        p.print("score", 100);  // resolves to print(String, int)

        // Widening: int widened to double if no exact match
        p.print((double) 5);    // print(double) called — explicit cast
    }
}

import java.util.*;

public class InterfacePolymorphism {

    interface Drawable {
        void draw();          // abstract by default
        default String color() { return "black"; } // default implementation
    }

    interface Resizable {
        void resize(double factor);
    }

    static class Circle implements Drawable, Resizable {
        double radius;
        Circle(double r) { radius = r; }
        @Override public void draw()   { System.out.println("Circle r=" + radius); }
        @Override public void resize(double f) { radius *= f; }
    }

    static class Square implements Drawable, Resizable {
        double side;
        Square(double s) { side = s; }
        @Override public void draw()   { System.out.println("Square s=" + side); }
        @Override public void resize(double f) { side *= f; }
        @Override public String color() { return "blue"; } // overrides default
    }

    // Works for ANYTHING that is Drawable — no knowledge of concrete type
    static void renderAll(List<Drawable> shapes) {
        for (Drawable d : shapes) {
            System.out.print(d.color() + " ");
            d.draw();
        }
    }

    // Works for ANYTHING that is Resizable
    static void doubleAll(List<? extends Resizable> shapes) {
        for (Resizable r : shapes) r.resize(2.0);
    }

    public static void main(String[] args) {
        List<Drawable> canvas = List.of(new Circle(5), new Square(3));
        renderAll(canvas); // black Circle r=5.0 / blue Square s=3.0

        List<Circle> circles = new ArrayList<>(List.of(new Circle(1), new Circle(2)));
        doubleAll(circles);
        circles.forEach(c -> System.out.println(c.radius)); // 2.0, 4.0
    }
}

import java.util.*;
import java.util.stream.*;

public class PolymorphicProcessing {

    interface Taxable {
        double basePrice();
        double taxRate();
        default double finalPrice() { return basePrice() * (1 + taxRate()); }
    }

    static class Food implements Taxable {
        String name; double price;
        Food(String name, double price) { this.name=name; this.price=price; }
        @Override public double basePrice() { return price; }
        @Override public double taxRate()   { return 0.05; } // 5% food tax
        public String toString() { return name; }
    }

    static class Electronics implements Taxable {
        String model; double price;
        Electronics(String model, double price) { this.model=model; this.price=price; }
        @Override public double basePrice() { return price; }
        @Override public double taxRate()   { return 0.18; } // 18% electronics tax
        public String toString() { return model; }
    }

    static class Luxury implements Taxable {
        String item; double price;
        Luxury(String item, double price) { this.item=item; this.price=price; }
        @Override public double basePrice() { return price; }
        @Override public double taxRate()   { return 0.28; } // 28% luxury tax
        public String toString() { return item; }
    }

    // Universal cart total — works for any Taxable mix
    static double cartTotal(List<Taxable> items) {
        return items.stream()
            .mapToDouble(Taxable::finalPrice) // polymorphic dispatch per item
            .sum();
    }

    public static void main(String[] args) {
        List<Taxable> cart = List.of(
            new Food("Apple",     2.00),
            new Electronics("Laptop", 1000.00),
            new Luxury("Watch",   500.00)
        );

        cart.forEach(t -> System.out.printf("%s: base=%.2f tax=%.0f%% final=%.2f%n",
            t, t.basePrice(), t.taxRate()*100, t.finalPrice()));

        System.out.printf("TOTAL: %.2f%n", cartTotal(cart));
        // Apple: 2.10, Laptop: 1180.00, Watch: 640.00 = 1822.10
    }
}

public class OverloadingPitfalls {

    static class Demo {
        void call(int i)     { System.out.println("int: "     + i); }
        void call(long l)    { System.out.println("long: "    + l); }
        void call(Integer i) { System.out.println("Integer: " + i); }
        void call(Object o)  { System.out.println("Object: "  + o); }
    }

    static class NullAmbiguity {
        void method(String s)  { System.out.println("String"); }
        void method(Integer i) { System.out.println("Integer"); }
        // method(null) → COMPILE ERROR: ambiguous — null fits both String and Integer
    }

    public static void main(String[] args) {
        Demo d = new Demo();

        int  prim = 5;
        Integer boxed = 5;

        d.call(prim);   // call(int)     — exact match, no boxing
        d.call(boxed);  // call(Integer) — exact match

        // Widening beats autoboxing:
        // int → long (widening) is preferred over int → Integer (boxing)
        // So call(int) would widen to call(long) before boxing to Integer
        // With only call(long) and call(Integer): widening wins

        d.call((long) prim); // call(long)  — explicit widen
        d.call((Object) boxed); // call(Object) — explicit upcast

        // Overloading is NOT polymorphic at runtime:
        Demo ref = new Demo(); // If Demo had a subclass, overloading still
        // resolves based on COMPILE-TIME type of the argument, not runtime type
    }
}

