public class Q1 {
    abstract static class Shape { abstract double area(); }

    static class Circle    extends Shape {
        double r; Circle(double r) { this.r=r; }
        @Override double area() { return Math.PI*r*r; }
    }
    static class Rectangle extends Shape {
        double w,h; Rectangle(double w,double h){this.w=w;this.h=h;}
        @Override double area() { return w*h; }
    }
    static class Triangle  extends Shape {
        double b,h; Triangle(double b,double h){this.b=b;this.h=h;}
        @Override double area() { return 0.5*b*h; }
    }

    public static double totalArea(Shape[] shapes) {
        double sum = 0;
        for (Shape s : shapes) sum += s.area();
        return sum;
    }

    public static void main(String[] args) {
        Shape[] arr = { new Circle(5), new Rectangle(4,6), new Triangle(3,8) };
        System.out.printf("%.2f%n", totalArea(arr)); // 114.54
    }
}

