problems.solutionCode:
import java.util.Arrays;

public class Q6 {
    interface Sorter { void sort(int[] arr); }

    static class BubbleSorter implements Sorter {
        @Override public void sort(int[] a) {
            for (int i=0;i<a.length-1;i++)
                for (int j=0;j<a.length-1-i;j++)
                    if (a[j]>a[j+1]) { int t=a[j]; a[j]=a[j+1]; a[j+1]=t; }
        }
    }
    static class SelectionSorter implements Sorter {
        @Override public void sort(int[] a) {
            for (int i=0;i<a.length;i++) {
                int min=i;
                for (int j=i+1;j<a.length;j++) if (a[j]<a[min]) min=j;
                int t=a[i]; a[i]=a[min]; a[min]=t;
            }
        }
    }
    static class InsertionSorter implements Sorter {
        @Override public void sort(int[] a) {
            for (int i=1;i<a.length;i++) {
                int key=a[i]; int j=i-1;
                while (j>=0&&a[j]>key) { a[j+1]=a[j]; j--; }
                a[j+1]=key;
            }
        }
    }

    static void sortAndPrint(int[] arr, Sorter strategy) {
        int[] copy = arr.clone();
        strategy.sort(copy);
        System.out.println(Arrays.toString(copy));
    }

    public static void main(String[] args) {
        int[] data = {5,3,8,1,9,2};
        sortAndPrint(data, new BubbleSorter());    // [1, 2, 3, 5, 8, 9]
        sortAndPrint(data, new SelectionSorter()); // [1, 2, 3, 5, 8, 9]
        sortAndPrint(data, new InsertionSorter()); // [1, 2, 3, 5, 8, 9]
    }
}

