public class Q9 {
    static class A { void go(Object o) { System.out.println("A-Object"); } }
    static class B extends A {
        @Override void go(Object o) { System.out.println("B-Object"); }
        void go(String s)           { System.out.println("B-String"); }
    }

    public static String[] predict() {
        // What does each print?
        // A a = new B(); a.go("hi");
        // B b = new B(); b.go("hi");
        return new String[]{"", ""};
    }
    public static void main(String[] args) {
        A a = new B(); a.go("hi");
        B b = new B(); b.go("hi");
    }
}

problems.solutionCode:
public class Q9 {
    static class A { void go(Object o) { System.out.println("A-Object"); } }
    static class B extends A {
        @Override void go(Object o) { System.out.println("B-Object"); }
        void go(String s)           { System.out.println("B-String"); }
    }

    public static String[] predict() {
        // A a=new B(); a.go("hi"):
        //   compile: A has only go(Object) → go(Object) selected
        //   runtime: object is B → B.go(Object) called → "B-Object"
        // B b=new B(); b.go("hi"):
        //   compile: B has go(Object) AND go(String) → String exact match → go(String)
        //   runtime: go(String) is not overridden → B.go(String) → "B-String"
        return new String[]{"B-Object", "B-String"};
    }
    public static void main(String[] args) {
        A a = new B(); a.go("hi"); // B-Object
        B b = new B(); b.go("hi"); // B-String
    }
}

