public class Q10 {
    static class Vehicle {
        String color; int wheels;
        Vehicle withColor(String c) { this.color = c; return this; }
        public String toString() { return color + " vehicle w=" + wheels; }
    }
    static class Car extends Vehicle {
        @Override Car withColor(String c) { this.color = c; return this; } // covariant
        Car withWheels(int n) { this.wheels = n; return this; }
    }

    public static void main(String[] args) {
        Car c = new Car();
        c.withColor("red").withWheels(4); // no cast needed — withColor returns Car
        System.out.println(c); // red vehicle w=4

        // Via Vehicle ref: withColor returns Vehicle — can't chain withWheels without cast
        Vehicle v = new Car();
        ((Car) v.withColor("blue")).withWheels(2); // needs cast
        System.out.println(v); // blue vehicle w=2
    }
}

