import java.util.*;

public class Q11 {
    interface EventListener { void onEvent(String event); }

    static class Logger  implements EventListener {
        @Override public void onEvent(String e) { System.out.println("LOG: "   + e); }
    }
    static class Emailer  implements EventListener {
        @Override public void onEvent(String e) { System.out.println("EMAIL: " + e); }
    }
    static class Auditor  implements EventListener {
        @Override public void onEvent(String e) { System.out.println("AUDIT: " + e); }
    }

    static class EventBus {
        private List<EventListener> listeners = new ArrayList<>();
        void register(EventListener l) { listeners.add(l); }
        void publish(String event) {
            for (EventListener l : listeners) l.onEvent(event);
        }
    }

    public static void main(String[] args) {
        EventBus bus = new EventBus();
        bus.register(new Logger()); bus.register(new Emailer()); bus.register(new Auditor());
        bus.publish("user.login");
    }
}

