public class Q15 {
    interface Formatter { String format(); }

    static class PlainText implements Formatter {
        String text; PlainText(String text) { this.text = text; }
        @Override public String format() { return text; }
    }
    static class BoldDecorator implements Formatter {
        Formatter inner; BoldDecorator(Formatter f) { inner = f; }
        @Override public String format() { return "**" + inner.format() + "**"; }
    }
    static class UpperCaseDecorator implements Formatter {
        Formatter inner; UpperCaseDecorator(Formatter f) { inner = f; }
        @Override public String format() { return inner.format().toUpperCase(); }
    }
    static class PrefixDecorator implements Formatter {
        String prefix; Formatter inner;
        PrefixDecorator(String p, Formatter f) { prefix=p; inner=f; }
        @Override public String format() { return prefix + inner.format(); }
    }

    public static void main(String[] args) {
        System.out.println(new PlainText("hello").format());                                          // hello
        System.out.println(new UpperCaseDecorator(new PlainText("hello")).format());                  // HELLO
        System.out.println(new BoldDecorator(new UpperCaseDecorator(new PlainText("hello"))).format()); // **HELLO**
        System.out.println(new PrefixDecorator("INFO: ", new BoldDecorator(new PlainText("hello"))).format()); // INFO: **hello**
    }
}

