public class Q16 {
    interface ShapeVisitor {
        double visit(Circle c);
        double visit(Square s);
        double visit(Triangle t);
    }
    abstract static class Shape { abstract double accept(ShapeVisitor v); }
    static class Circle   extends Shape { double r; Circle(double r){this.r=r;}
        @Override public double accept(ShapeVisitor v) { return v.visit(this); } }
    static class Square   extends Shape { double s; Square(double s){this.s=s;}
        @Override public double accept(ShapeVisitor v) { return v.visit(this); } }
    static class Triangle extends Shape { double s; Triangle(double s){this.s=s;}
        @Override public double accept(ShapeVisitor v) { return v.visit(this); } }

    static class PerimeterVisitor implements ShapeVisitor {
        @Override public double visit(Circle c)   { return 2 * Math.PI * c.r; }
        @Override public double visit(Square s)   { return 4 * s.s; }
        @Override public double visit(Triangle t) { return 3 * t.s; } // equilateral
    }

    public static void main(String[] args) {
        Shape[] shapes = {new Circle(5), new Square(4), new Triangle(3)};
        ShapeVisitor pv = new PerimeterVisitor();
        for (Shape s : shapes)
            System.out.printf("%.2f%n", s.accept(pv));
        // 31.42 (2π*5), 16.00 (4*4), 9.00 (3*3)
    }
}

