import java.util.*;

public class Q17 {
    interface Transformer<T> { T transform(T input); }

    static class TrimTransformer       implements Transformer<String> {
        @Override public String transform(String s) { return s.trim(); }
    }
    static class UpperCaseTransformer  implements Transformer<String> {
        @Override public String transform(String s) { return s.toUpperCase(); }
    }
    static class ReplaceTransformer    implements Transformer<String> {
        String from, to;
        ReplaceTransformer(String f, String t) { from=f; to=t; }
        @Override public String transform(String s) { return s.replace(from, to); }
    }

    static class Pipeline {
        private List<Transformer<String>> steps = new ArrayList<>();
        Pipeline add(Transformer<String> t) { steps.add(t); return this; }
        String apply(String input) {
            String s = input;
            for (Transformer<String> t : steps) s = t.transform(s);
            return s;
        }
    }

    public static void main(String[] args) {
        Pipeline p = new Pipeline()
            .add(new TrimTransformer())
            .add(new UpperCaseTransformer())
            .add(new ReplaceTransformer("WORLD", "JAVA"));
        System.out.println(p.apply("  hello world  ")); // HELLO JAVA
    }
}

