import java.util.*;

public class Q20 {
    interface TreeNode { void print(String indent); }

    static class Leaf implements TreeNode {
        String value;
        Leaf(String value) { this.value = value; }
        @Override public void print(String indent) {
            System.out.println(indent + value);
        }
    }

    static class Branch implements TreeNode {
        String name;
        List<TreeNode> children;
        Branch(String name, List<TreeNode> children) { this.name=name; this.children=children; }
        @Override public void print(String indent) {
            System.out.println(indent + name + "/");
            for (TreeNode child : children) child.print(indent + "  ");
        }
    }

    public static void main(String[] args) {
        TreeNode tree = new Branch("root", List.of(
            new Branch("A", List.of(new Leaf("A1"), new Leaf("A2"))),
            new Branch("B", List.of(new Leaf("B1"))),
            new Leaf("C")
        ));
        tree.print("");
    }
}
